      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  if (!f.getItemValue('ky_truoc_tu') && !f.getItemValue('ky_truoc_den')) setDefaultDate(f.getItem('ky_nay_tu'));
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      var x = f.getItemValue('mau_bc');
      g._hiddenFields = [
        {Fields: 'lk_kn_nt, lk_kt_nt', Value: (x == '10' || x == '20' || x == '30' || x == '40' || x == '50' || x == '80')},
        {Fields: 'ky_naynt, ky_truocnt', Value: (x == '10' || x == '20' || x == '30' || x == '40' || x == '60')},
        {Fields: 'lk_kn, lk_kt', Value: (x == '10' || x == '40' || x == '50' || x == '80')},
        {Fields: 'ky_nay, ky_truoc', Value: x == '20' || x == '60')}
      ];
      g._hiddenForms = [
        {Form: [1, 2, 3, 5, 6, 7, 9, 10, 11, 13, 14, 15, 18, 19, 20, 22, 23, 24, 26, 27, 28, 30, 31, 32], Value: (x == '10' || x == '50')},
        {Form: [0, 2, 3, 4, 6, 7, 8, 10, 11, 12, 14, 15, 17, 19, 20, 21, 23, 24, 25, 27, 28, 29, 31, 32], Value: (x == '20' || x == '60')},
        {Form: [0, 1, 3, 4, 5, 7, 8, 9, 11, 12, 13, 15, 17, 18, 20, 21, 22, 24, 25, 26, 28, 29, 30, 32], Value: (x == '30' || x == '70')},
        {Form: [0, 1, 2, 4, 5, 6, 8, 9, 10, 12, 13, 14, 17, 18, 19, 21, 22, 23, 25, 26, 27, 29, 30, 31], Value: (x == '40' || x == '80')}
      ];
      var dFrom = f.getItem('ky_nay_tu').value, dTo = f.getItem('ky_nay_den').value;
      var index = f.getItem('form').selectedIndex, y = f.getItem('form').options, formName = y[index].text;
      g._alterTitle = [null, [['%f1', formName, true], ['%d1', dFrom, true], ['%d2', dTo, true]]];
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}
function setDefaultDate(o) {
  var f = o.parentForm;
  var dateFrom = f.getItemValue('ky_nay_tu', null, null, true), dateTo = f.getItemValue('ky_nay_den', null, null, true);
  var sFrom = new Date(dateFrom.getFullYear() - 1, dateFrom.getMonth(), dateFrom.getDate());
  f.setItemValue('ky_truoc_tu', sFrom);
  var sTo = new Date(dateTo.getFullYear() - 1, dateTo.getMonth(), dateTo.getDate());
  f.setItemValue('ky_truoc_den', sTo);
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255)), index;
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
    if (!index && f._defaultForm == value[i]) index = i;
  }
  if (!index) index = 0;
  o.options[index].selected = true;
}
